const { diagnosis, ageGroup, researchType, context, regions } = $input.first().json.body.data;

const pubmedQuery = `Latest peer-reviewed research and systematic reviews for ${diagnosis}. ${ageGroup ? `Patient age group: ${ageGroup}.` : ''} ${researchType !== 'all' ? `Focus on: ${researchType}` : ''} Include PubMed references from 2023-2026. ${context || ''}`;

const clinicalTrialsQuery = `Active and recruiting clinical trials for ${diagnosis}. Include ClinicalTrials.gov entries, trial phase, enrollment status, locations. ${ageGroup ? `Age group: ${ageGroup}` : ''} ${regions?.length ? `Regions: ${regions.join(', ')}` : ''}`;

const treatmentQuery = `Current standard of care and experimental treatment options for ${diagnosis}. Include treatment efficacy data, side effects, and recent advances. ${ageGroup ? `Patient age group: ${ageGroup}.` : ''} ${context || ''}`;

return {
  json: {
    diagnosis, ageGroup, researchType, context, regions,
    queries: { pubmed: pubmedQuery, clinicalTrials: clinicalTrialsQuery, treatment: treatmentQuery }
  }
};

const items = $input.all();
const parts = [];

for (const item of items) {
  const content = item.json?.choices?.[0]?.message?.content;
  if (content) parts.push(content);
}

const firstItem = $input.first().json;
const diagnosis = firstItem.diagnosis || firstItem.body?.data?.diagnosis || 'N/A';
const ageGroup = firstItem.ageGroup || firstItem.body?.data?.ageGroup || '';
const researchType = firstItem.researchType || firstItem.body?.data?.researchType || '';

const userMessage = `დიაგნოზი: ${diagnosis}\nასაკობრივი ჯგუფი: ${ageGroup}\nკვლევის ტიპი: ${researchType}\n\nინტერნეტ ძიების შედეგები:\n${parts.join('\n\n---\n\n')}`;

return { json: { userMessage } };

const raw = $input.first().json;
const text = raw.content?.[0]?.text || '';

let parsed = null;

// Try code fence
const fenceMatch = text.match(/```(?:json)?\s*(\{[\s\S]*?\})\s*```/);
if (fenceMatch) {
  try { parsed = JSON.parse(fenceMatch[1]); } catch(e) {}
}

// Try full text
if (!parsed) {
  try { parsed = JSON.parse(text.trim()); } catch(e) {}
}

if (parsed && (parsed.meta || parsed.items || parsed.sections)) {
  return { json: parsed };
}

// Fallback: return text as summary
return { json: { meta: 'ძიების შედეგები', items: [], summary: text } };
